contexto:
Lista de medicamentos prescritos, com nome, dose e via:
{{lista_medicamentos}}

Idade do paciente:
{{idade}}

Função renal estimada:
{{funcao_renal}}

Condições crônicas relevantes:
{{condicoes}}

formato_saida:
Retorne JSON com o seguinte schema:

{
  "interacoes_identificadas": [
    {
      "medicamentos_envolvidos": ["string"],
      "severidade": "contraindicada | maior | moderada | menor",
      "mecanismo": "string com 1 a 3 linhas",
      "manifestacao_esperada": "string com 1 a 2 linhas",
      "conduta_esperada": "string com 1 a 2 linhas",
      "necessita_validacao_farmaceutica": true | false
    }
  ],
  "ajustes_por_funcao_renal": [
    {
      "medicamento": "string",
      "ajuste_recomendado": "string",
      "justificativa": "string"
    }
  ],
  "lacunas_de_informacao": [
    "string descrevendo informação faltante"
  ],
  "necessita_revisao_farmaceutica_global": true | false
}
